export interface PolicyStateV1 { id: string; premium: number; }
export interface PolicyStateV2 { id: string; premium: number; currency: string; }
export interface PolicyStateV3 { id: string; premium: number; currency: string; activated: boolean; }

export type CurrentState = PolicyStateV3;

export interface Snapshot<S> { version: number; state: S; }

export const CURRENT_VERSION = 3;

function v1Tov2(s: PolicyStateV1): PolicyStateV2 {
  return { ...s, currency: "USD" };
}

function v2Tov3(s: PolicyStateV2): PolicyStateV3 {
  return { ...s, activated: false };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentState> {
  let version = snap.version;
  let state: unknown = snap.state;

  if (version === 1) {
    state = v1Tov2(state as PolicyStateV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as PolicyStateV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) {
    throw new Error(`Unsupported snapshot version ${snap.version}`);
  }
  const upgraded = state as CurrentState;
  if (typeof upgraded.id !== "string" || typeof upgraded.activated !== "boolean") {
    throw new Error("Upgraded snapshot fails shape check");
  }
  return { version: CURRENT_VERSION, state: upgraded };
}
