export interface QuoteV1 { id: string; total: number; }
export interface QuoteV2 { id: string; total: number; currency: string; }
export interface QuoteV3 { id: string; total: number; currency: string; expiresAt: string; }

export type CurrentQuote = QuoteV3;
export interface Snapshot<S> { version: number; state: S; }
export const CURRENT_VERSION = 3;

export class UnknownSnapshotError extends Error {}

type Upgrader = (state: unknown) => unknown;

const upgraders: Record<number, Upgrader> = {
  1: (s) => ({ ...(s as QuoteV1), currency: "USD" }),
  2: (s) => ({ ...(s as QuoteV2), expiresAt: "1970-01-01T00:00:00Z" }),
};

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentQuote> {
  let v = snap.version;
  let state: unknown = snap.state;
  while (v < CURRENT_VERSION) {
    const fn = upgraders[v];
    if (!fn) throw new UnknownSnapshotError(`v${v}`);
    state = fn(state);
    v += 1;
  }
  if (v !== CURRENT_VERSION) throw new UnknownSnapshotError(`v${v}`);
  return { version: CURRENT_VERSION, state: state as CurrentQuote };
}
