```typescript
export type ProcessEvent =
  | { type: "ClaimFiled"; claimId: string; amount: number }
  | { type: "ClaimAssessed"; claimId: string; adjuster: string }
  | { type: "ClaimApproved"; claimId: string; at: string };

export type ProcessCommand =
  | { type: "AssignAdjuster"; claimId: string }
  | { type: "ScheduleReview"; claimId: string; adjuster: string };

export type ProcessState =
  | { status: "idle" }
  | { status: "waiting-assessment"; claimId: string }
  | { status: "waiting-decision"; claimId: string; adjuster: string }
  | { status: "done"; claimId: string };

export const initial: ProcessState = { status: "idle" };

// Caller folds saga state with reduce<ProcessState>(stepReducer, initial) and
// dispatches any emitted command to a downstream CommandHandler.
export function step(
  state: ProcessState,
  event: ProcessEvent,
): { next: ProcessState; command: ProcessCommand | null } {
  switch (event.type) {
    case "ClaimFiled":
      return {
        next: { status: "waiting-assessment", claimId: event.claimId },
        command: { type: "AssignAdjuster", claimId: event.claimId },
      };
    case "ClaimAssessed":
      if (state.status !== "waiting-assessment") return { next: state, command: null };
      return {
        next: { status: "waiting-decision", claimId: state.claimId, adjuster: event.adjuster },
        command: { type: "ScheduleReview", claimId: state.claimId, adjuster: event.adjuster },
      };
    case "ClaimApproved":
      if (state.status !== "waiting-decision") return { next: state, command: null };
      return { next: { status: "done", claimId: state.claimId }, command: null };
    default: {
      const _n: never = event;
      return { next: state, command: null };
    }
  }
}
