import { Effect } from "effect";

export type UnderwriterState =
  | { status: "none" }
  | { status: "assessing"; caseId: string; adjuster: string }
  | { status: "approved"; caseId: string; adjuster: string; at: string }
  | { status: "declined"; caseId: string; reason: string };

export type UnderwriterCommand =
  | { type: "assess"; caseId: string; adjuster: string }
  | { type: "approve"; at: string }
  | { type: "decline"; reason: string };

export type UnderwriterEvent =
  | { type: "CaseAssessed"; caseId: string; adjuster: string }
  | { type: "CaseApproved"; at: string }
  | { type: "CaseDeclined"; reason: string };

export class UnderwriterError extends Error {}

const initial: UnderwriterState = { status: "none" };

export function decide(c: UnderwriterCommand, s: UnderwriterState): UnderwriterEvent[] {
  switch (c.type) {
    case "assess":
      if (s.status !== "none") throw new UnderwriterError("EXISTS");
      return [{ type: "CaseAssessed", caseId: c.caseId, adjuster: c.adjuster }];
    case "approve":
      if (s.status !== "assessing") throw new UnderwriterError("NOT_ASSESSING");
      return [{ type: "CaseApproved", at: c.at }];
    case "decline":
      if (s.status !== "assessing") throw new UnderwriterError("NOT_ASSESSING");
      return [{ type: "CaseDeclined", reason: c.reason }];
    default: { const _n: never = c; throw new UnderwriterError("UNKNOWN"); }
  }
}

export function evolve(s: UnderwriterState, e: UnderwriterEvent): UnderwriterState {
  switch (e.type) {
    case "CaseAssessed":
      return { status: "assessing", caseId: e.caseId, adjuster: e.adjuster };
    case "CaseApproved":
      if (s.status !== "assessing") return s;
      return { status: "approved", caseId: s.caseId, adjuster: s.adjuster, at: e.at };
    case "CaseDeclined":
      if (s.status !== "assessing") return s;
      return { status: "declined", caseId: s.caseId, reason: e.reason };
    default: { const _n: never = e; return s; }
  }
}

export interface EventStore<E> {
  readStream(s: string): AsyncIterable<{ revision: bigint; event: E }>;
  appendToStream(
    s: string, e: readonly E[], o: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
}

export const handle = (
  command: UnderwriterCommand,
  ctx: { streamName: string; eventStore: EventStore<UnderwriterEvent> },
) =>
  Effect.gen(function* () {
    const loaded = yield* Effect.promise(async () => {
      let state = initial;
      let rev: bigint | "no_stream" = "no_stream";
      for await (const rec of ctx.eventStore.readStream(ctx.streamName)) {
        state = evolve(state, rec.event);
        rev = rec.revision;
      }
      return { state, rev };
    });
    const events = decide(command, loaded.state);
    yield* Effect.promise(() =>
      ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: loaded.rev }),
    );
  });
